// Accessing system services through the Application Framework layer
import android.app.Activity;
import android.content.Context;
import android.location.LocationManager;
import android.net.ConnectivityManager;
import android.os.Bundle;

public class SystemServiceDemo extends Activity {
 @Override
 protected void onCreate(Bundle savedInstanceState) {
 super.onCreate(savedInstanceState);
 setContentView(R.layout.activity_main);

 // Activity Manager - manages app lifecycle
 android.app.ActivityManager activityManager =
 (android.app.ActivityManager) getSystemService(Context.ACTIVITY_SERVICE);

 // Location Manager - accesses GPS via HAL layer
 LocationManager locationManager =
 (LocationManager) getSystemService(Context.LOCATION_SERVICE);

 // Connectivity Manager - network status via Linux kernel
 ConnectivityManager connectivityManager =
 (ConnectivityManager) getSystemService(Context.CONNECTIVITY_SERVICE);

 // Window Manager - manages display via SurfaceFlinger
 android.view.WindowManager windowManager =
 (android.view.WindowManager) getSystemService(Context.WINDOW_SERVICE);
 }
}

// Accessing native C/C++ libraries through JNI
// This demonstrates the Native Libraries layer of Android architecture
public class NativeLibDemo extends Activity {

 // Load native library (compiled C/C++ code)
 static {
 System.loadLibrary("native-lib");
 }

 // Declare native method (implemented in C/C++)
 public native String stringFromJNI();
 public native int computeFromNative(int a, int b);

 @Override
 protected void onCreate(Bundle savedInstanceState) {
 super.onCreate(savedInstanceState);
 setContentView(R.layout.activity_main);

 // Call native method - bridges Java and native layers
 String result = stringFromJNI();
 int sum = computeFromNative(10, 20);

 // Using Android's built-in native libraries
 // OpenGL ES for graphics (native library)
 // SQLite for database (native library)
 // WebKit for web rendering (native library)
 }
}
